import os
import json
from flask import Flask, request, jsonify
from kafka import KafkaProducer

KAFKA_BOOTSTRAP_SERVERS = os.getenv("KAFKA_BOOTSTRAP_SERVERS", "localhost:9092").split(",")
KAFKA_CLIENT_ID = os.getenv("KAFKA_CLIENT_ID", "flexible-event-publisher")
KAFKA_ACKS = os.getenv("KAFKA_ACKS", "1")
KAFKA_LINGER_MS = int(os.getenv("KAFKA_LINGER_MS", "5"))
KAFKA_RETRIES = int(os.getenv("KAFKA_RETRIES", "3"))
KAFKA_MAX_IN_FLIGHT = int(os.getenv("KAFKA_MAX_IN_FLIGHT_REQUESTS_PER_CONNECTION", "5"))
KAFKA_REQUEST_TIMEOUT_MS = int(os.getenv("KAFKA_REQUEST_TIMEOUT_MS", "30000"))

app = Flask(__name__)

producer = KafkaProducer(
    bootstrap_servers=KAFKA_BOOTSTRAP_SERVERS,
    client_id=KAFKA_CLIENT_ID,
    acks=KAFKA_ACKS,
    linger_ms=KAFKA_LINGER_MS,
    retries=KAFKA_RETRIES,
    max_in_flight_requests_per_connection=KAFKA_MAX_IN_FLIGHT,
    request_timeout_ms=KAFKA_REQUEST_TIMEOUT_MS,
    value_serializer=lambda v: v if isinstance(v, (bytes, bytearray)) else str(v).encode("utf-8"),
    key_serializer=lambda v: v if isinstance(v, (bytes, bytearray)) else (None if v is None else str(v).encode("utf-8")),
)

@app.route("/publish", methods=["POST"])
def publish():
    topic = request.args.get("topic", "")
    if not topic:
        return jsonify({"error": "missing topic parameter"}), 400

    key = request.args.get("key", None)

    if request.is_json:
        payload = request.get_json(silent=True)
        if payload is None:
            message = request.data or b""
        else:
            message = json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    else:
        message = request.data or request.form.get("message", "").encode("utf-8")

    future = producer.send(topic, key=key, value=message)
    record_metadata = future.get(timeout=10)

    return jsonify(
        {
            "topic": record_metadata.topic,
            "partition": record_metadata.partition,
            "offset": record_metadata.offset,
        }
    ), 200

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"}), 200

if __name__ == "__main__":
    host = os.getenv("HOST", "0.0.0.0")
    port = int(os.getenv("PORT", "8080"))
    app.run(host=host, port=port)